// extractBearerToken extracts the JWT from the Authorization header.
func extractBearerToken(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", errors.New("authorization header is required")
	}

	// Expect "Bearer <token>" format.
	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
		return "", errors.New("authorization header must be in 'Bearer <token>' format")
	}

	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", errors.New("bearer token is empty")
	}

	// Basic sanity check: JWT should have exactly 3 parts separated by dots.
	jwtParts := strings.Split(token, ".")
	if len(jwtParts) != 3 {
		return "", errors.New("malformed JWT token")
	}

	// Reject tokens that are unreasonably large (prevent DoS via large tokens).
	if len(token) > 8192 {
		return "", errors.New("token exceeds maximum allowed size")
	}

	return token, nil
}

